import os
import subprocess
import sys
from multiprocessing import Pool

frames_dir = "/tmp/frames3"
frames = sorted([f for f in os.listdir(frames_dir) if f.endswith('.png')], key=lambda x: int(x.split('_')[1].split('.')[0]))

def ocr_frame(frame_file):
    """Extract the last command from a frame."""
    frame_path = os.path.join(frames_dir, frame_file)
    result = subprocess.run(["tesseract", frame_path, "stdout"], capture_output=True, text=True)
    text = result.stdout
    cmd_lines = []
    for line in text.split('\n'):
        stripped = line.strip()
        if stripped.startswith('>') and len(stripped) > 1:
            cmd = stripped[1:].strip()
            if cmd:
                cmd_lines.append(cmd)
    # Return last command (being typed)
    if cmd_lines:
        return (frame_file, cmd_lines[-1])
    return (frame_file, None)

print(f"Processing {len(frames)} frames with multiprocessing...", file=sys.stderr)
with Pool(4) as p:
    results = p.map(ocr_frame, frames)

# Sort by frame number and extract sequence of typed commands
results.sort(key=lambda x: int(x[0].split('_')[1].split('.')[0]))

# Track when typing command changes to infer completed commands
prev_cmd = None
typing_sequence = []
for frame_file, cmd in results:
    if cmd and cmd != prev_cmd:
        print(f"{cmd}")
        if prev_cmd:
            typing_sequence.append(prev_cmd)
        prev_cmd = cmd

# Add the last command
if prev_cmd:
    typing_sequence.append(prev_cmd)

print(f"\nTotal commands: {len(typing_sequence)}", file=sys.stderr)
for i, cmd in enumerate(typing_sequence):
    print(f"{i+1}. {cmd}", file=sys.stderr)

with open("/app/solution.txt", "w") as f:
    for cmd in typing_sequence:
        f.write(cmd + "\n")
print(f"Saved to /app/solution.txt", file=sys.stderr)
ENDSCRIPT
